#!/usr/bin/perl

use strict;
use warnings;
use CGI qw(:standard);
use Digest::MD5 qw(md5_hex);

# --- Configuration ---
# Path to the user data file (flat file "database")
# IMPORTANT: In a production environment, ensure this file is outside the web root
# and has appropriate permissions to prevent unauthorized access.
my $DATA_FILE = "/tmp/legacy_users.txt"; 

# --- Main CGI Logic ---
my $q = CGI->new;

print $q->header;
