    print $q->hidden(-name => 'action', -value => 'register');
    print $q->p("Username: ", $q->textfield(-name => 'username'));
    print $q->p("Password: ", $q->password_field(-name => 'password'));
    print $q->p($q->submit(-value => 'Register User'));
    print $q->end_form;

