sub handle_register {
    my $q = shift;
    my $username = $q->param('username');
    my $password = $q->param('password');

    unless ($username && $password) {
        print $q->p("Error: Username and password are required for registration.");
        return;
    }

    my %users = read_user_data();
    if (exists $users{$username}) {
        print $q->p("Error: User '", $q->b($username), "' already exists. Please choose a different username.");
        return;
    }

    # Hash the password using md5_hex for legacy compatibility
    my $hashed_password = md5_hex($password);

    # Append to the data file
    if (open my $fh, '>>', $DATA_FILE) {
        print $fh "$username:$hashed_password\n";
        close $fh;
        print $q->p("User '", $q->b($username), "' registered successfully!");
    } else {
        print $q->p("Error: Could not open data file for writing: $!");
    }
}

sub handle_login {
    my $q = shift;
    my $username = $q->param('username');
    my $password = $q->param('password');

    unless ($username && $password) {
        print $q->p("Error: Username and password are required for login.");
        return;
    }

    my %users = read_user_data();
    unless (exists $users{$username}) {
        print $q->p("Login failed: User '", $q->b($username), "' not found.");
        return;
    }

    my $stored_hash = $users{$username};
    # Hash the provided password using md5_hex to compare with the stored hash
    my $input_hash = md5_hex($password);

    if ($stored_hash eq $input_hash) {
        print $q->p("Login successful for user '", $q->b($username), "'!");
    } else {
        print $q->p("Login failed: Incorrect password for user '", $q->b($username), "'.");
    }
}

# Reads user data from the flat file into a hash
sub read_user_data {
    my %users;
    if (open my $fh, '<', $DATA_FILE) {
        while (my $line = <$fh>) {
            chomp $line;
            my ($user, $hash) = split /:/, $line, 2;
            $users{$user} = $hash if $user && $hash;
        }
        close $fh;
    } else {
        # File might not exist yet, which is fine for the first run
        warn "Could not open user data file '$DATA_FILE': $!" unless -e $DATA_FILE;
    }
    return %users;
}